private fun writeJournal(): Unit = synchronized(lock) {
    journalWriter?.close()

    fileSystem.write(journalFileTmp) {
        writeUtf8(MAGIC).writeByte('\n'.code)
        writeUtf8(VERSION).writeByte('\n'.code)
        writeDecimalLong(appVersion.toLong()).writeByte('\n'.code)
        writeDecimalLong(valueCount.toLong()).writeByte('\n'.code)
        writeByte('\n'.code)

        for (entry in lruEntries.values) {
            if (entry.currentEditor != null) {
                writeUtf8(DIRTY)
                writeByte(' '.code)
                writeUtf8(entry.key)
                writeByte('\n'.code)
            } else {
                writeUtf8(CLEAN)
                writeByte(' '.code)
                writeUtf8(entry.key)
                entry.writeLengths(this)
                writeByte('\n'.code)
            }
        }
    }

    if (fileSystem.exists(journalFile)) {
        fileSystem.atomicMove(journalFile, journalFileBackup)
        fileSystem.atomicMove(journalFileTmp, journalFile)
        fileSystem.delete(journalFileBackup)
    } else {
        fileSystem.atomicMove(journalFileTmp, journalFile)
    }

    journalWriter = newJournalWriter()
    operationsSinceRewrite = 0
    hasJournalErrors = false
    mostRecentRebuildFailed = false
}

private fun SerialDescriptor.scalarTypeName(annotations: List<Annotation> = emptyList()): String {
    val integerType = annotations.filterIsInstance<ProtoType>().firstOrNull()?.type ?: ProtoIntegerType.DEFAULT

    if (kind == SerialKind.CONTEXTUAL) {
        return "bytes"
    }

    if (kind is StructureKind.LIST && getElementDescriptor(0).kind == PrimitiveKind.BYTE) {
        return "bytes"
    }

    return when (kind as PrimitiveKind) {
        PrimitiveKind.BOOLEAN -> "bool"
        PrimitiveKind.BYTE, PrimitiveKind.CHAR, PrimitiveKind.SHORT, PrimitiveKind.INT ->
            when (integerType) {
                ProtoIntegerType.DEFAULT -> "int32"
                ProtoIntegerType.SIGNED -> "sint32"
                ProtoIntegerType.FIXED -> "fixed32"
            }
        PrimitiveKind.LONG ->
            when (integerType) {
                ProtoIntegerType.DEFAULT -> "int64"
                ProtoIntegerType.SIGNED -> "sint64"
                ProtoIntegerType.FIXED -> "fixed64"
            }
        PrimitiveKind.FLOAT -> "float"
        PrimitiveKind.DOUBLE -> "double"
        PrimitiveKind.STRING -> "string"
    }
}

internal fun formatIpv6(groups: IntArray): String {
    require(groups.size == 8) { "IPv6 address must have 8 groups, got ${groups.size}" }

    var bestStart = -1
    var bestLength = 0
    var currentStart = -1
    var currentLength = 0
    for (i in groups.indices) {
        if (groups[i] == 0) {
            if (currentStart == -1) currentStart = i
            currentLength++
            if (currentLength > bestLength) {
                bestStart = currentStart
                bestLength = currentLength
            }
        } else {
            currentStart = -1
            currentLength = 0
        }
    }
    if (bestLength < 2) {
        bestStart = -1
        bestLength = 0
    }

    return buildString {
        var i = 0
        while (i < 8) {
            if (i == bestStart) {
                append("::")
                i += bestLength
                continue
            }
            if (i > 0 && i != bestStart + bestLength) append(':')
            append(groups[i].toString(16))
            i++
        }
    }
}

@OptIn(ExperimentalForeignApi::class)
    private fun hasOnePinnedCertificate(
        certificates: List<SecCertificateRef>
    ): Boolean = certificates.any { certificate ->
        val publicKey = certificate.getPublicKeyBytes() ?: return@any false
        // Lazily compute the hashes for each public key.
        var sha1: String? = null
        var sha256: String? = null

        pinnedCertificates.any { pin ->
            when (pin.hashAlgorithm) {
                LegacyCertificatesInfo.HASH_ALGORITHM_SHA_256 -> {
                    if (sha256 == null) {
                        sha256 = publicKey.toSha256String()
                    }

                    pin.hash == sha256
                }
                LegacyCertificatesInfo.HASH_ALGORITHM_SHA_1 -> {
                    if (sha1 == null) {
                        sha1 = publicKey.toSha1String()
                    }

                    pin.hash == sha1
                }
                else -> {
                    println("CertificatePinner: Unsupported hashAlgorithm: ${pin.hashAlgorithm}")
                    false
                }
            }
        }
    }

public fun new(pattern: String, pin: String): LegacyPinnedCertificate {
    require(
        (pattern.startsWith("*.") && pattern.indexOf("*", 1) == -1) ||
            (pattern.startsWith("**.") && pattern.indexOf("*", 2) == -1) ||
            pattern.indexOf("*") == -1
    ) {
        "Unexpected pattern: $pattern"
    }
    val canonicalPattern = pattern.lowercase()
    return when {
        pin.startsWith(HASH_ALGORITHM_SHA_1) -> {
            val hash = pin.substring(HASH_ALGORITHM_SHA_1.length)
            LegacyPinnedCertificate(
                pattern = canonicalPattern,
                hashAlgorithm = HASH_ALGORITHM_SHA_1,
                hash = hash
            )
        }

        pin.startsWith(HASH_ALGORITHM_SHA_256) -> {
            val hash = pin.substring(HASH_ALGORITHM_SHA_256.length)
            LegacyPinnedCertificate(
                pattern = canonicalPattern,
                hashAlgorithm = HASH_ALGORITHM_SHA_256,
                hash = hash
            )
        }

        else -> throw IllegalArgumentException(
            "Pins must start with '$HASH_ALGORITHM_SHA_256' or '$HASH_ALGORITHM_SHA_1': $pin"
        )
    }
}

